print(f'{a} | {b}')

def run(sources):
    broken = [s['name'] for s in sources if s['n_in'] != s['n_clean'] + s['n_quarantine']]
    if broken:
        return f"ERROR sources={','.join(broken)}", 1
    return 'OK', 0

good = [
    {'name': 'clients.csv', 'n_in': 3, 'n_clean': 2, 'n_quarantine': 1},
    {'name': 'transactions.json', 'n_in': 2, 'n_clean': 2, 'n_quarantine': 0},
]
compensated_bad = [
    {'name': 'clients.csv', 'n_in': 6, 'n_clean': 4, 'n_quarantine': 1},
    {'name': 'transactions.json', 'n_in': 4, 'n_clean': 5, 'n_quarantine': 0},
]
for label, src in [('good', good), ('compensated_bad', compensated_bad)]:
    msg, code = run(src)
    print(label, '→', f'{msg}/{code}')
